Medium.solution:
function solution(input: string): string {
  const [condLine, arrLine] = input.trim().split('\n');
  const [cond, valStr] = condLine.split(' ');
  const val = Number(valStr);
  const nums = arrLine.split(/\s+/).map(Number);

  let result: number[] = [];
  if (cond === 'gt') result = nums.filter(n => n > val);
  else if (cond === 'lt') result = nums.filter(n => n < val);
  else if (cond === 'eq') result = nums.filter(n => n === val);

  return result.join(' ');
}

